// ══════════ HELPERS ══════════
function fmtTgl(s) {
  if (!s) return "-";
  const [y,m,d] = s.split("-");
  const b = ["","Jan","Feb","Mar","Apr","Mei","Jun","Jul","Agt","Sep","Okt","Nov","Des"];
  return `${parseInt(d)} ${b[parseInt(m)]} ${y}`;
}
function fmtDT(ts) {
  if (!ts) return "-";
  return new Date(ts).toLocaleString("id-ID",{day:"2-digit",month:"short",year:"numeric",hour:"2-digit",minute:"2-digit"});
}
function today() { return new Date().toISOString().split("T")[0]; }

// ══════════ STORAGE ══════════
async function dbLoad() {
  try {
    const res = await window.storage.get(STORAGE_KEY, true);
    return res ? JSON.parse(res.value) : { izin: [] };
  } catch { return { izin: [] }; }
}
async function dbSave(data) {
  await window.storage.set(STORAGE_KEY, JSON.stringify(data), true);
}

