// ══════════ MAIN APP ══════════
export default function App() {
  const [user, setUser] = useState(null);
  const [db, setDb] = useState({ izin: [] });
  const [tab, setTab] = useState("");
  const [loading, setLoading] = useState(false);
  const [loadMsg, setLoadMsg] = useState("Memuat…");
  const [toasts, setToasts] = useState([]);
  const [modal, setModal] = useState(null); // null | "detail" | "tolak"
  const [selectedIzin, setSelectedIzin] = useState(null);
  const [clock, setClock] = useState(new Date().toLocaleTimeString("id-ID"));

  // login state
  const [selUser, setSelUser] = useState("");
  const [pw, setPw] = useState("");
  const [pwShow, setPwShow] = useState(false);
  const [loginErr, setLoginErr] = useState(false);

  // form state
  const [form, setForm] = useState({ tanggal:today(), keperluan:KEPERLUAN[0], jamKeluar:"", jamKembali:"", tujuan:"", keterangan:"", atasanId:USERS.find(u=>u.role==="atasan"||u.role==="keduanya")?.id||1 });

  // tolak state
  const [alasanTolak, setAlasanTolak] = useState("");

  useEffect(() => {
    const t = setInterval(() => setClock(new Date().toLocaleTimeString("id-ID")), 1000);
    return () => clearInterval(t);
  }, []);

  const addToast = useCallback((msg, err=false) => {
    const id = Date.now();
    setToasts(p => [...p, { id, msg, err }]);
    setTimeout(() => setToasts(p => p.filter(t => t.id !== id)), 3500);
  }, []);

  const load = useCallback(async (msg="Memuat data…") => {
    setLoadMsg(msg); setLoading(true);
    const data = await dbLoad();
    setDb(data); setLoading(false);
    return data;
  }, []);

  const save = useCallback(async (data, msg="Menyimpan…") => {
    setLoadMsg(msg); setLoading(true);
    try {
      await dbSave(data);
      setDb(data);
      setLoading(false);
      return true;
    } catch(e) {
      setLoading(false);
      addToast("Gagal menyimpan ke server: " + e.message, true);
      return false;
    }
  }, [addToast]);

  // LOGIN
  const doLogin = async () => {
    setLoginErr(false);
    const uid = parseInt(selUser);
    if (!uid) { addToast("Pilih nama pengguna!", true); return; }
    const u = USERS.find(x => x.id === uid);
    if (!u || pw !== u.pw) { setLoginErr(true); return; }
    const data = await load("Memuat data…");
    setUser(u);
    const defaultTab = u.role === "admin" ? "dashboard" : u.role === "keduanya" ? "form" : u.role === "pegawai" ? "form" : "approval";
    setTab(defaultTab);
    setDb(data);
  };

  const logout = () => {
    if (!confirm("Keluar dari CABLAKA?")) return;
    setUser(null); setPw(""); setSelUser(""); setLoginErr(false); setDb({ izin: [] });
  };

  // TABS
  // Helper: apakah user bisa jadi atasan (approve)?
  const isAtasan = (u) => u && (u.role === "atasan" || u.role === "keduanya");
  const isPegawai = (u) => u && (u.role === "pegawai" || u.role === "keduanya");

  const getTabs = () => {
    if (!user) return [];
    if (user.role === "admin") return [
      { key:"dashboard", icon:"📊", label:"Dashboard" },
      { key:"semua",     icon:"📋", label:"Semua Pengajuan" },
      { key:"pegawai",   icon:"👥", label:"Data Pegawai" },
    ];
    const tabs = [];
    if (isPegawai(user)) {
      tabs.push({ key:"form",    icon:"📝", label:"Ajukan Izin" });
      tabs.push({ key:"riwayat", icon:"📋", label:"Izin Saya" });
    }
    if (isAtasan(user)) {
      tabs.push({ key:"approval", icon:"⏳", label:"Perlu Disetujui", badge: db.izin.filter(x=>x.atasanId===user.id&&x.status==="menunggu").length });
      tabs.push({ key:"done",     icon:"✅", label:"Sudah Diproses" });
      tabs.push({ key:"semua",    icon:"📋", label:"Semua Pengajuan" });
    }
    return tabs;
  };

  const refreshData = async () => {
    await load("Memuat ulang…");
    addToast("Data diperbarui!");
  };

  // AJUKAN IZIN
  const ajukanIzin = async () => {
    if (!form.tanggal || !form.jamKeluar || !form.jamKembali || !form.tujuan.trim()) { addToast("Lengkapi semua field wajib!", true); return; }
    if (form.jamKembali <= form.jamKeluar) { addToast("Estimasi kembali harus setelah jam keluar!", true); return; }
    const newItem = { id:Date.now(), pegawaiId:user.id, pegawaiNama:user.nama, pegawaiJabatan:user.jabatan, pegawaiNip:user.nip,
      ...form, atasanId:parseInt(form.atasanId), status:"menunggu", createdAt:Date.now(), updatedAt:null, alasanTolak:"", disetujuiOleh:"" };
    const fresh = await load("Memuat data terbaru…");
    const updated = { izin: [newItem, ...fresh.izin] };
    const ok = await save(updated, "Menyimpan pengajuan…");
    if (ok) { addToast("Pengajuan berhasil dikirim!"); setTab("riwayat"); setForm(f => ({ ...f, jamKeluar:"", jamKembali:"", tujuan:"", keterangan:"", tanggal:today() })); }
  };

  // SETUJUI
  const setujui = async (id) => {
    const izin = db.izin.find(x => x.id === id);
    if (!izin || !confirm(`Setujui izin ${izin.pegawaiNama}?`)) return;
    const fresh = await load("Memuat…");
    const updated = { izin: fresh.izin.map(x => x.id === id ? { ...x, status:"disetujui", disetujuiOleh:user.nama, updatedAt:Date.now() } : x) };
    const ok = await save(updated, "Menyimpan…");
    if (ok) { addToast("Izin disetujui!"); setTab("approval"); }
  };

  // TOLAK
  const konfirmasiTolak = async () => {
    if (!alasanTolak.trim()) { addToast("Isi alasan penolakan!", true); return; }
    const id = selectedIzin;
    const fresh = await load("Memuat…");
    const updated = { izin: fresh.izin.map(x => x.id === id ? { ...x, status:"ditolak", alasanTolak, updatedAt:Date.now() } : x) };
    const ok = await save(updated, "Menyimpan…");
    if (ok) { addToast("Izin ditolak."); setModal(null); setAlasanTolak(""); setTab("approval"); }
  };

  // HAPUS
  const hapus = async (id) => {
    if (!confirm("Hapus data ini secara permanen?")) return;
    const fresh = await load("Memuat…");
    const updated = { izin: fresh.izin.filter(x => x.id !== id) };
    const ok = await save(updated, "Menghapus…");
    if (ok) { addToast("Data dihapus."); }
  };

  // CETAK SURAT
  const cetakSurat = (id) => {
    const x = db.izin.find(i => i.id === id);
    if (!x || x.status !== "disetujui") { addToast("Hanya izin yang disetujui yang dapat dicetak.", true); return; }
    const at = USERS.find(u => u.id === x.atasanId);
    const noSurat = `PA-Pwt/${String(x.id).slice(-4)}/${new Date(x.createdAt).getFullYear()}`;
    const printEl = document.getElementById("print-area");
    printEl.innerHTML = `<div style="padding:40px;font-family:'Times New Roman',serif;font-size:13px;line-height:1.9;">
      <div style="display:flex;align-items:center;gap:20px;border-bottom:3px double #000;padding-bottom:12px;margin-bottom:20px;">
        <img src="data:image/jpeg;base64," style="width:64px;height:64px;object-fit:contain;" alt="PA Purwokerto"/>
        <div><h2 style="font-size:16px;font-weight:900;text-transform:uppercase;">PENGADILAN AGAMA PURWOKERTO</h2>
        <p style="font-size:12px;">Jl. Gerilya No. 17 Purwokerto, Kabupaten Banyumas, Jawa Tengah 53114</p>
        <p style="font-size:12px;">Telp. (0281) 635438 | www.pa-purwokerto.go.id</p></div>
      </div>
      <div style="text-align:center;margin:16px 0;"><b style="font-size:14px;text-transform:uppercase;border-bottom:1px solid #000;padding-bottom:2px;">SURAT IZIN KELUAR KANTOR</b></div>
      <div style="text-align:center;font-size:12px;margin-bottom:18px;">Nomor: ${noSurat}</div>
      <p>Yang bertanda tangan di bawah ini:</p>
      <table style="margin:10px 0 10px 20px;"><tr><td style="width:180px;">Nama</td><td style="width:12px;">:</td><td><b>${at?.nama||"—"}</b></td></tr>
      <tr><td>NIP</td><td>:</td><td>${at?.nip||"—"}</td></tr><tr><td>Jabatan</td><td>:</td><td>${at?.jabatan||"—"}</td></tr></table>
      <p>Memberikan izin keluar kantor kepada pegawai berikut:</p>
      <table style="margin:10px 0 10px 20px;"><tr><td style="width:180px;">Nama</td><td style="width:12px;">:</td><td><b>${x.pegawaiNama}</b></td></tr>
      <tr><td>NIP</td><td>:</td><td>${x.pegawaiNip}</td></tr><tr><td>Jabatan</td><td>:</td><td>${x.pegawaiJabatan}</td></tr></table>
      <p>Untuk keperluan sebagai berikut:</p>
      <table style="margin:10px 0 10px 20px;">
        <tr><td style="width:180px;">Keperluan</td><td style="width:12px;">:</td><td>${x.keperluan}</td></tr>
        <tr><td>Tujuan / Lokasi</td><td>:</td><td>${x.tujuan}</td></tr>
        <tr><td>Tanggal</td><td>:</td><td>${fmtTgl(x.tanggal)}</td></tr>
        <tr><td>Jam Keluar</td><td>:</td><td>${x.jamKeluar} WIB</td></tr>
        <tr><td>Estimasi Kembali</td><td>:</td><td>${x.jamKembali} WIB</td></tr>
        ${x.keterangan?`<tr><td>Keterangan</td><td>:</td><td>${x.keterangan}</td></tr>`:""}
      </table>
      <p>Demikian surat izin ini dibuat untuk dipergunakan sebagaimana mestinya.</p>
      <div style="display:flex;justify-content:flex-end;margin-top:32px;">
        <div style="text-align:center;min-width:220px;">
          <p>Purwokerto, ${fmtTgl(today())}</p><p>${at?.jabatan||"Pimpinan"}</p>
          <br><br><br>
          <p><b><u>${at?.nama||"—"}</u></b></p>
          <p style="font-size:12px;">NIP. ${at?.nip||"—"}</p>
        </div>
      </div>
    </div>`;
    setTimeout(() => window.print(), 300);
  };

  // ══════════ RENDER ══════════
  const tabs = getTabs();
  const dataRiwayat = db.izin.filter(x => x.pegawaiId === user?.id);
  const dataPending = db.izin.filter(x => x.atasanId === user?.id && x.status === "menunggu");
  const dataDone    = db.izin.filter(x => x.atasanId === user?.id && x.status !== "menunggu");

  const BadgeStatus = ({ s }) => {
    const label = s==="disetujui" ? "✅ Disetujui" : s==="ditolak" ? "❌ Ditolak" : "⏳ Menunggu";
    return <span style={S.badge(s)}>{label}</span>;
  };

  const Btn = ({ variant="primary", sm=false, full=false, onClick, children, style={} }) => (
    <button style={{ ...S.btn(variant,sm), ...(full?S.btnFull:{}), ...style }} onClick={onClick}>{children}</button>
  );

  const Card = ({ title, right, children, noPad=false }) => (
    <div style={S.card}>
      {title && <div style={S.cardHeader}><span style={S.cardTitle}>{title}</span>{right}</div>}
      <div style={noPad ? {} : S.cardBody}>{children}</div>
    </div>
  );

  const Th = ({ children }) => <th style={S.th}>{children}</th>;
  const Td = ({ children, mono=false, small=false }) => (
    <td style={{ ...S.td, ...(mono?{fontFamily:"monospace",fontSize:12}:{}), ...(small?{fontSize:11,color:"#718096"}:{}) }}>{children}</td>
  );

  const EmptyState = ({ icon, msg }) => (
    <div style={S.empty}><div style={{ fontSize:40, marginBottom:10 }}>{icon}</div><p style={{ fontSize:13 }}>{msg}</p></div>
  );

  const RefreshBtn = () => <Btn variant="ghost" sm onClick={refreshData}>🔄 Refresh</Btn>;

  // ── TAB CONTENT ──
  const renderTab = () => {
    if (tab === "form") return (
      <div style={{ maxWidth:680 }}>
        <div style={S.alertInfo}>👋 Halo, <b>{user.nama}</b>. Isi form di bawah untuk mengajukan izin keluar kantor.</div>
        <Card title="📝 Form Pengajuan Izin Keluar">
          <div style={S.formRow}>
            <div style={S.formGroup}>
              <label style={S.formLabel}>Tanggal Izin *</label>
              <input style={S.formControl} type="date" value={form.tanggal} onChange={e=>setForm(f=>({...f,tanggal:e.target.value}))} />
            </div>
            <div style={S.formGroup}>
              <label style={S.formLabel}>Keperluan *</label>
              <select style={S.formControl} value={form.keperluan} onChange={e=>setForm(f=>({...f,keperluan:e.target.value}))}>
                {KEPERLUAN.map(k=><option key={k}>{k}</option>)}
              </select>
            </div>
          </div>
          <div style={S.formRow}>
            <div style={S.formGroup}>
              <label style={S.formLabel}>Jam Keluar *</label>
              <input style={S.formControl} type="time" value={form.jamKeluar} onChange={e=>setForm(f=>({...f,jamKeluar:e.target.value}))} />
            </div>
            <div style={S.formGroup}>
              <label style={S.formLabel}>Estimasi Kembali *</label>
              <input style={S.formControl} type="time" value={form.jamKembali} onChange={e=>setForm(f=>({...f,jamKembali:e.target.value}))} />
            </div>
          </div>
          <div style={S.formGroup}>
            <label style={S.formLabel}>Tujuan / Lokasi *</label>
            <input style={S.formControl} type="text" placeholder="cth: RSUD Banyumas, BRI Purwokerto…" value={form.tujuan} onChange={e=>setForm(f=>({...f,tujuan:e.target.value}))} />
          </div>
          <div style={S.formGroup}>
            <label style={S.formLabel}>Keterangan Tambahan</label>
            <textarea style={{...S.formControl,resize:"vertical",minHeight:70}} placeholder="Deskripsi tambahan jika diperlukan…" value={form.keterangan} onChange={e=>setForm(f=>({...f,keterangan:e.target.value}))} />
          </div>
          <div style={S.formGroup}>
            <label style={S.formLabel}>Diajukan kepada *</label>
            <select style={S.formControl} value={form.atasanId} onChange={e=>setForm(f=>({...f,atasanId:e.target.value}))}>
              {USERS.filter(u=>u.role==="atasan"||u.role==="keduanya").map(u=><option key={u.id} value={u.id}>{u.nama}</option>)}
            </select>
          </div>
          <Btn variant="primary" full onClick={ajukanIzin}>🚀 Kirim Pengajuan</Btn>
        </Card>
      </div>
    );

    if (tab === "riwayat") {
      const s = { total:dataRiwayat.length, dis:dataRiwayat.filter(x=>x.status==="disetujui").length, dit:dataRiwayat.filter(x=>x.status==="ditolak").length, men:dataRiwayat.filter(x=>x.status==="menunggu").length };
      return <>
        <div style={S.statsGrid}>
          {[["📋 Total",s.total,"#276749"],["✅ Disetujui",s.dis,"#276749"],["❌ Ditolak",s.dit,"#c53030"],["⏳ Menunggu",s.men,"#c9a84c"]].map(([l,n,c])=>(
            <div key={l} style={S.statTile}><div style={S.statNum(c)}>{n}</div><div style={S.statLabel}>{l}</div></div>
          ))}
        </div>
        <Card title="📋 Riwayat Izin Saya" right={<RefreshBtn/>} noPad>
          {!dataRiwayat.length ? <EmptyState icon="📭" msg="Belum ada pengajuan izin"/> :
          <div style={{overflowX:"auto"}}><table style={{width:"100%",borderCollapse:"collapse",fontSize:13}}>
            <thead><tr><Th>#</Th><Th>Tanggal</Th><Th>Keperluan</Th><Th>Tujuan</Th><Th>Jam</Th><Th>Status</Th><Th>Aksi</Th></tr></thead>
            <tbody>{dataRiwayat.map((x,i)=><tr key={x.id}>
              <Td mono>{String(i+1).padStart(2,"0")}</Td>
              <Td>{fmtTgl(x.tanggal)}</Td><Td>{x.keperluan}</Td><Td>{x.tujuan}</Td>
              <Td mono>{x.jamKeluar}–{x.jamKembali}</Td>
              <Td><BadgeStatus s={x.status}/></Td>
              <Td><div style={{display:"flex",gap:5}}>
                <Btn variant="info" sm onClick={()=>{setSelectedIzin(x.id);setModal("detail");}}>🔍</Btn>
                {x.status==="disetujui"&&<Btn variant="ghost" sm onClick={()=>cetakSurat(x.id)}>🖨️</Btn>}
              </div></Td>
            </tr>)}</tbody>
          </table></div>}
        </Card>
      </>;
    }

    if (tab === "approval") return (
      <Card title={<>⏳ Perlu Disetujui <span style={{background:"#c9a84c",color:"#fff",padding:"2px 10px",borderRadius:99,fontSize:12,fontWeight:700}}>{dataPending.length}</span></>} right={<RefreshBtn/>}>
        {!dataPending.length ? <EmptyState icon="🎉" msg="Tidak ada pengajuan yang menunggu"/> :
        dataPending.map(x=>(
          <div key={x.id} style={S.pendCard}>
            <div style={{display:"flex",justifyContent:"space-between",alignItems:"flex-start",gap:10,flexWrap:"wrap"}}>
              <div>
                <div style={{fontSize:15,fontWeight:700}}>{x.pegawaiNama}</div>
                <div style={{fontSize:11,color:"#718096"}}>{x.pegawaiJabatan}</div>
              </div>
              <div style={{display:"flex",gap:6,flexWrap:"wrap"}}>
                <Btn variant="success" sm onClick={()=>setujui(x.id)}>✅ Setujui</Btn>
                <Btn variant="danger" sm onClick={()=>{setSelectedIzin(x.id);setAlasanTolak("");setModal("tolak");}}>❌ Tolak</Btn>
                <Btn variant="info" sm onClick={()=>{setSelectedIzin(x.id);setModal("detail");}}>🔍</Btn>
              </div>
            </div>
            <div style={{display:"flex",gap:14,marginTop:10,flexWrap:"wrap",fontSize:12,color:"#718096"}}>
              <span>📅 {fmtTgl(x.tanggal)}</span><span>🕐 {x.jamKeluar}–{x.jamKembali}</span><span>📍 {x.tujuan}</span>
            </div>
            <div style={{fontSize:13,color:"#4a5568",marginTop:8,fontStyle:"italic"}}>📌 {x.keperluan}{x.keterangan?" — "+x.keterangan:""}</div>
            <div style={{fontSize:11,color:"#cbd5e0",marginTop:6}}>Diajukan {fmtDT(x.createdAt)}</div>
          </div>
        ))}
      </Card>
    );

    if (tab === "done") return (
      <Card title="✅ Sudah Diproses" right={<RefreshBtn/>} noPad>
        {!dataDone.length ? <EmptyState icon="📭" msg="Belum ada"/> :
        <div style={{overflowX:"auto"}}><table style={{width:"100%",borderCollapse:"collapse",fontSize:13}}>
          <thead><tr><Th>Nama</Th><Th>Tanggal</Th><Th>Keperluan</Th><Th>Status</Th><Th>Aksi</Th></tr></thead>
          <tbody>{dataDone.map(x=><tr key={x.id}>
            <Td><b>{x.pegawaiNama}</b><br/><span style={{fontSize:11,color:"#718096"}}>{x.pegawaiJabatan}</span></Td>
            <Td>{fmtTgl(x.tanggal)}</Td><Td>{x.keperluan}</Td>
            <Td><BadgeStatus s={x.status}/></Td>
            <Td><div style={{display:"flex",gap:5}}>
              <Btn variant="info" sm onClick={()=>{setSelectedIzin(x.id);setModal("detail");}}>🔍</Btn>
              {x.status==="disetujui"&&<Btn variant="ghost" sm onClick={()=>cetakSurat(x.id)}>🖨️</Btn>}
            </div></Td>
          </tr>)}</tbody>
        </table></div>}
      </Card>
    );

    if (tab === "semua") return (
      <Card title="📋 Semua Pengajuan" right={<RefreshBtn/>} noPad>
        {!db.izin.length ? <EmptyState icon="📭" msg="Belum ada data"/> :
        <div style={{overflowX:"auto"}}><table style={{width:"100%",borderCollapse:"collapse",fontSize:13}}>
          <thead><tr><Th>#</Th><Th>Nama</Th><Th>Tanggal</Th><Th>Keperluan</Th><Th>Tujuan</Th><Th>Jam</Th><Th>Diajukan ke</Th><Th>Status</Th><Th>Aksi</Th></tr></thead>
          <tbody>{db.izin.map((x,i)=>{
            const at=USERS.find(u=>u.id===x.atasanId);
            return <tr key={x.id}>
              <Td mono>{String(i+1).padStart(2,"0")}</Td>
              <Td><b>{x.pegawaiNama}</b><br/><span style={{fontSize:11,color:"#718096"}}>{x.pegawaiJabatan}</span></Td>
              <Td>{fmtTgl(x.tanggal)}</Td><Td>{x.keperluan}</Td><Td>{x.tujuan}</Td>
              <Td mono>{x.jamKeluar}–{x.jamKembali}</Td>
              <Td small>{at?.nama||"-"}</Td>
              <Td><BadgeStatus s={x.status}/></Td>
              <Td><div style={{display:"flex",gap:5}}>
                <Btn variant="info" sm onClick={()=>{setSelectedIzin(x.id);setModal("detail");}}>🔍</Btn>
                {x.status==="disetujui"&&<Btn variant="ghost" sm onClick={()=>cetakSurat(x.id)}>🖨️</Btn>}
                {user.role==="admin"&&<Btn variant="danger" sm onClick={()=>hapus(x.id)}>🗑️</Btn>}
              </div></Td>
            </tr>;
          })}</tbody>
        </table></div>}
      </Card>
    );

    if (tab === "dashboard") {
      const todayStr = today();
      const hariIni = db.izin.filter(x=>x.tanggal===todayStr&&x.status==="disetujui");
      const s = { total:db.izin.length, dis:db.izin.filter(x=>x.status==="disetujui").length, dit:db.izin.filter(x=>x.status==="ditolak").length, men:db.izin.filter(x=>x.status==="menunggu").length };
      return <>
        <div style={S.statsGrid}>
          {[["📋 Total",s.total,"#276749"],["✅ Disetujui",s.dis,"#276749"],["❌ Ditolak",s.dit,"#c53030"],["⏳ Menunggu",s.men,"#c9a84c"]].map(([l,n,c])=>(
            <div key={l} style={S.statTile}><div style={S.statNum(c)}>{n}</div><div style={S.statLabel}>{l}</div></div>
          ))}
        </div>
        <Card title={`🔔 Izin Keluar Hari Ini — ${fmtTgl(todayStr)}`} right={<RefreshBtn/>} noPad>
          {!hariIni.length ? <EmptyState icon="🏢" msg="Tidak ada pegawai keluar hari ini"/> :
          <div style={{overflowX:"auto"}}><table style={{width:"100%",borderCollapse:"collapse",fontSize:13}}>
            <thead><tr><Th>Nama</Th><Th>Keperluan</Th><Th>Tujuan</Th><Th>Jam</Th></tr></thead>
            <tbody>{hariIni.map(x=><tr key={x.id}>
              <Td><b>{x.pegawaiNama}</b></Td><Td>{x.keperluan}</Td><Td>{x.tujuan}</Td><Td mono>{x.jamKeluar}–{x.jamKembali}</Td>
            </tr>)}</tbody>
          </table></div>}
        </Card>
      </>;
    }

    if (tab === "pegawai") return (
      <Card title="👥 Data Pegawai" noPad>
        <div style={{overflowX:"auto"}}><table style={{width:"100%",borderCollapse:"collapse",fontSize:13}}>
          <thead><tr><Th>#</Th><Th>Nama</Th><Th>NIP</Th><Th>Jabatan</Th><Th>Role</Th><Th>Password</Th><Th>Total Izin</Th><Th>Disetujui</Th></tr></thead>
          <tbody>{USERS.map((u,i)=>{
            const my=db.izin.filter(x=>x.pegawaiId===u.id);
            return <tr key={u.id}>
              <Td mono>{String(i+1).padStart(2,"0")}</Td>
              <Td>{u.avatar} <b>{u.nama}</b></Td>
              <Td mono>{u.nip}</Td>
              <Td>{u.jabatan}</Td>
              <Td><span style={{...S.badge(u.role==="atasan"||u.role==="keduanya"?"disetujui":"menunggu")}}>{u.role==="admin"?"Admin":u.role==="keduanya"?"Pegawai + Atasan":u.role==="atasan"?"Atasan":"Pegawai"}</span></Td>
              <Td mono>{u.pw}</Td>
              <Td>{my.length}</Td>
              <Td>{my.filter(x=>x.status==="disetujui").length}</Td>
            </tr>;
          })}</tbody>
        </table></div>
      </Card>
    );

    return null;
  };

  // MODAL DETAIL
  const detailIzin = modal==="detail" && selectedIzin ? db.izin.find(x=>x.id===selectedIzin) : null;
  const detailAtasan = detailIzin ? USERS.find(u=>u.id===detailIzin.atasanId) : null;
  const DR = ({l,v}) => <tr><td style={{padding:"7px 12px",borderBottom:"1px solid #f0f4f8",fontWeight:600,color:"#718096",width:150,fontSize:12,textTransform:"uppercase",letterSpacing:.3}}>{l}</td><td style={{padding:"7px 12px",borderBottom:"1px solid #f0f4f8"}} dangerouslySetInnerHTML={{__html:v}}></td></tr>;

  return (
    <div style={S.app}>
      {/* LOADING */}
      {loading && <div style={{position:"fixed",inset:0,background:"rgba(255,255,255,.85)",zIndex:9999,display:"flex",alignItems:"center",justifyContent:"center",flexDirection:"column",gap:12}}>
        <div style={{width:36,height:36,border:"3px solid #e2e8f0",borderTopColor:"#276749",borderRadius:"50%",animation:"spin .7s linear infinite"}}/>
        <style>{`@keyframes spin{to{transform:rotate(360deg)}}`}</style>
        <div style={{fontSize:13,color:"#718096",fontWeight:600}}>{loadMsg}</div>
      </div>}

      {/* TOASTS */}
      <div style={S.toastWrap}>
        {toasts.map(t=><div key={t.id} style={S.toast(t.err)}>{t.err?"⚠️":"✅"} {t.msg}</div>)}
      </div>

      {/* HEADER */}
      <header style={S.header}>
        <div style={S.brandLogo}><img src={LOGO_SRC} style={{width:"100%",height:"100%",objectFit:"contain"}} alt="CABLAKA"/></div>
        <div>
          <div style={S.brandName}>CABLAKA</div>
          <div style={S.brandSub}>Catatan Berkas Layanan Keluar Kantor</div>
        </div>
        <div style={{marginLeft:"auto",display:"flex",alignItems:"center",gap:10}}>
          <span style={{fontFamily:"monospace",fontSize:13,color:"#9ae6b4"}}>{clock}</span>
          {user && <div style={S.userPill} onClick={logout}>
            <div style={S.userAvatar}>{user.avatar}</div>
            <div>
              <div style={{fontSize:12,fontWeight:600,color:"#fff"}}>{user.nama}</div>
              <div style={{fontSize:10,color:"#9ae6b4"}}>{user.role==="admin"?"Admin":user.role==="keduanya"?"Pegawai & Atasan":user.role==="atasan"?"Pimpinan":"Pegawai"}</div>
            </div>
          </div>}
        </div>
      </header>

      {/* LOGIN */}
      {!user && <div style={S.loginScreen}>
        <div style={S.loginWrap}>
          <div style={{textAlign:"center",marginBottom:32}}>
            <div style={S.bigLogo}><img src={LOGO_SRC} style={{width:"100%",height:"100%",objectFit:"contain"}} alt="CABLAKA"/></div>
            <h1 style={{fontSize:30,fontWeight:800,color:"#fff",letterSpacing:-1}}>CABLA<span style={{color:"#c9a84c"}}>KA</span></h1>
            <p style={{fontSize:12,color:"#9ae6b4",marginTop:6}}>Catatan Berkas Layanan Keluar Kantor · Pengadilan Agama Purwokerto</p>
          </div>
          <div style={S.loginCard}>
            <h3 style={{fontSize:14,fontWeight:700,color:"#fff",marginBottom:18}}>🔐 Masuk ke Sistem</h3>
            <label style={S.loginLabel}>Pilih Pengguna</label>
            <select style={S.loginSelect} value={selUser} onChange={e=>{setSelUser(e.target.value);setLoginErr(false);setPw("");}}>
              <option value="">— Pilih nama Anda —</option>
              {USERS.map(u=><option key={u.id} value={u.id}>{u.nama} — {u.role==="pegawai"?"Pegawai":u.role==="atasan"?"Pimpinan":"Admin"}</option>)}
            </select>
            <label style={S.loginLabel}>Password</label>
            <div style={{position:"relative",marginBottom:4}}>
              <input style={S.loginInput} type={pwShow?"text":"password"} placeholder="Masukkan password…" value={pw}
                onChange={e=>setPw(e.target.value)} onKeyDown={e=>e.key==="Enter"&&doLogin()}/>
              <button style={{position:"absolute",right:12,top:"50%",transform:"translateY(-50%)",background:"none",border:"none",cursor:"pointer",fontSize:16,color:"rgba(255,255,255,.5)"}} onClick={()=>setPwShow(p=>!p)}>{pwShow?"🙈":"👁️"}</button>
            </div>
            {loginErr && <div style={S.loginErr}>❌ Password salah. Coba lagi.</div>}
            <button style={S.loginBtn} onClick={doLogin}>Masuk →</button>
          </div>
        </div>
      </div>}

      {/* MAIN */}
      {user && <div style={S.layout}>
        {/* SIDEBAR */}
        <nav style={S.sidebar}>
          <div style={S.sidebarLabel}>Menu</div>
          {tabs.map(t=>(
            <button key={t.key} style={S.sidebarBtn(tab===t.key)} onClick={()=>setTab(t.key)}>
              <span style={{fontSize:16,width:22,textAlign:"center"}}>{t.icon}</span>
              {t.label}
              {t.badge>0 && <span style={S.sbBadge}>{t.badge}</span>}
            </button>
          ))}
          <div style={{flex:1}}/>
          <button style={{...S.sidebarBtn(false),color:"#c53030"}} onClick={logout}><span style={{fontSize:16,width:22,textAlign:"center"}}>🔓</span>Keluar</button>
        </nav>

        {/* CONTENT */}
        <main style={S.content}>{renderTab()}</main>
      </div>}

      {/* MODAL DETAIL */}
      {modal==="detail" && detailIzin && (
        <div style={S.overlay} onClick={()=>setModal(null)}>
          <div style={S.modal} onClick={e=>e.stopPropagation()}>
            <button style={S.modalClose} onClick={()=>setModal(null)}>✕</button>
            <div style={S.modalTitle}>📋 Detail Izin Keluar</div>
            <table style={{width:"100%",borderCollapse:"collapse",fontSize:13}}>
              <tbody>
                <DR l="👤 Nama" v={detailIzin.pegawaiNama}/>
                <DR l="🪪 NIP" v={detailIzin.pegawaiNip}/>
                <DR l="💼 Jabatan" v={detailIzin.pegawaiJabatan}/>
                <DR l="📅 Tanggal" v={fmtTgl(detailIzin.tanggal)}/>
                <DR l="🕐 Jam Keluar" v={detailIzin.jamKeluar+" WIB"}/>
                <DR l="🕓 Est. Kembali" v={detailIzin.jamKembali+" WIB"}/>
                <DR l="📌 Keperluan" v={detailIzin.keperluan}/>
                <DR l="📍 Tujuan" v={detailIzin.tujuan}/>
                <DR l="📝 Keterangan" v={detailIzin.keterangan||"—"}/>
                <DR l="👨‍💼 Diajukan ke" v={detailAtasan?.nama||"—"}/>
                <DR l="📊 Status" v={detailIzin.status==="disetujui"?'<span style="background:#c6f6d5;color:#276749;padding:3px 10px;border-radius:99px;font-size:11px;font-weight:700;">✅ Disetujui</span>':detailIzin.status==="ditolak"?'<span style="background:#fed7d7;color:#c53030;padding:3px 10px;border-radius:99px;font-size:11px;font-weight:700;">❌ Ditolak</span>':'<span style="background:#fef3c7;color:#92400e;padding:3px 10px;border-radius:99px;font-size:11px;font-weight:700;">⏳ Menunggu</span>'}/>
                {detailIzin.status==="disetujui"&&<DR l="✅ Disetujui oleh" v={detailIzin.disetujuiOleh}/>}
                {detailIzin.status==="ditolak"&&<DR l="❌ Alasan Tolak" v={`<span style="color:#c53030">${detailIzin.alasanTolak}</span>`}/>}
                <DR l="📆 Pengajuan" v={fmtDT(detailIzin.createdAt)}/>
                {detailIzin.updatedAt&&<DR l="🔄 Diperbarui" v={fmtDT(detailIzin.updatedAt)}/>}
              </tbody>
            </table>
            {detailIzin.status==="disetujui"&&<div style={{marginTop:18}}><Btn variant="gold" onClick={()=>{cetakSurat(detailIzin.id);setModal(null);}}>🖨️ Cetak Surat Izin</Btn></div>}
          </div>
        </div>
      )}

      {/* MODAL TOLAK */}
      {modal==="tolak" && (
        <div style={S.overlay} onClick={()=>setModal(null)}>
          <div style={{...S.modal,maxWidth:420}} onClick={e=>e.stopPropagation()}>
            <button style={S.modalClose} onClick={()=>setModal(null)}>✕</button>
            <div style={S.modalTitle}>❌ Alasan Penolakan</div>
            <div style={S.formGroup}>
              <label style={S.formLabel}>Alasan *</label>
              <textarea style={{...S.formControl,resize:"vertical",minHeight:90}} placeholder="Jelaskan alasan penolakan…" value={alasanTolak} onChange={e=>setAlasanTolak(e.target.value)}/>
            </div>
            <Btn variant="danger" full onClick={konfirmasiTolak}>Konfirmasi Penolakan</Btn>
          </div>
        </div>
      )}

      {/* PRINT AREA */}
      <div id="print-area" style={{display:"none"}}/>
      <style>{`@media print{body>*:not(#print-area){display:none!important;}#print-area{display:block!important;position:absolute;left:0;top:0;width:100%;}}`}</style>
    </div>
  );
}
